code:
import ast
from typing import Any

# Safety limits
MAX_STR_LEN = 5000        # Maximum length of resulting strings
MAX_NUM_ABS = 10**12      # Maximum absolute numeric value allowed
MAX_SOURCE_LEN = 1000     # Maximum length of input source text


class _UnsafeScript(Exception):
    """Internal exception to signal blocked/unsafe evaluation."""
    pass


def parse_user_script(script_str: str) -> str:
    """
    Safely parse and evaluate a tiny Python expression consisting only of:
      - numeric literals (int, float)
      - string literals
      - binary operations: +, -, *, /, //, %
      - unary operations: +, -

    For strings:
      - concatenation with +
      - repetition with * (string * int or int * string), non-negative counts only

    Returns:
      - str: the result of the evaluation as a string
      - 'Execution Blocked!' if the input is unsafe or any error occurs
    """
    # Validate input type and size
    if not isinstance(script_str, str):
        return 'Execution Blocked!'
    if len(script_str) > MAX_SOURCE_LEN:
        return 'Execution Blocked!'

    # Parse as a single expression
    try:
        tree = ast.parse(script_str, mode='eval')
    except Exception:
        return 'Execution Blocked!'

    # Validate that only allowed AST nodes are present
    if not _is_ast_safe(tree):
        return 'Execution Blocked!'

    # Evaluate safely
    try:
        value = _eval_node(tree.body)
    except Exception:
        return 'Execution Blocked!'

    # Convert result to string
    try:
        if isinstance(value, str):
            if len(value) > MAX_STR_LEN:
                return 'Execution Blocked!'
            return value
        if isinstance(value, (int, float)):
            if not _is_number_in_bounds(value):
                return 'Execution Blocked!'
            return str(value)
    except Exception:
        return 'Execution Blocked!'

    return 'Execution Blocked!'


def _is_ast_safe(node: ast.AST) -> bool:
    """
    Ensure only a very restricted subset of Python AST nodes is used.
    Disallows names, calls, attributes, subscripts, comprehensions, etc.
    """
    allowed_bin_ops = (ast.Add, ast.Sub, ast.Mult, ast.Div, ast.FloorDiv, ast.Mod)
    allowed_unary_ops = (ast.UAdd, ast.USub)

    def _check(n: ast.AST) -> bool:
        if isinstance(n, ast.Expression):
            return _check(n.body)

        if isinstance(n, ast.BinOp):
            if not isinstance(n.op, allowed_bin_ops):
                return False
            return _check(n.left) and _check(n.right)

        if isinstance(n, ast.UnaryOp):
            if not isinstance(n.op, allowed_unary_ops):
                return False
            return _check(n.operand)

        if isinstance(n, ast.Constant):
            v = n.value
            if isinstance(v, (int, float)):
                return True
            if isinstance(v, str):
                return len(v) <= MAX_STR_LEN
            # Disallow complex, bytes, bool, None, etc.
            return False

        # Disallow everything else (Name, Call, Attribute, Subscript, etc.)
        return False

    return _check(node)


def _is_number(x: Any) -> bool:
    # Exclude bool (which is a subclass of int in Python)
    return isinstance(x, (int, float)) and not isinstance(x, bool)


def _is_number_in_bounds(x: Any) -> bool:
    if not _is_number(x):
        return False
    # Disallow NaN/inf for floats
    if isinstance(x, float):
        if x != x:  # NaN
            return False
        if x == float('inf') or x == float('-inf'):
            return False
    try:
        return abs(x) <= MAX_NUM_ABS
    except Exception:
        return False


def _eval_node(node: ast.AST) -> Any:
    if isinstance(node, ast.Constant):
        v = node.value
        if isinstance(v, (int, float)):
            return v
        if isinstance(v, str):
            if len(v) > MAX_STR_LEN:
                raise _UnsafeScript()
            return v
        raise _UnsafeScript()

    if isinstance(node, ast.UnaryOp):
        val = _eval_node(node.operand)
        if isinstance(node.op, ast.UAdd):
            if _is_number(val):
                return +val
            raise _UnsafeScript()
        if isinstance(node.op, ast.USub):
            if _is_number(val):
                res = -val
                if _is_number_in_bounds(res):
                    return res
            raise _UnsafeScript()
        raise _UnsafeScript()

    if isinstance(node, ast.BinOp):
        left = _eval_node(node.left)
        right = _eval_node(node.right)

        # String operations
        if isinstance(left, str) or isinstance(right, str):
            # Only allow + (concat) and * (repeat)
            if isinstance(node.op, ast.Add):
                if isinstance(left, str) and isinstance(right, str):
                    res = left + right
                    if len(res) <= MAX_STR_LEN:
                        return res
                    raise _UnsafeScript()
                raise _UnsafeScript()

            if isinstance(node.op, ast.Mult):
                if isinstance(left, str) and isinstance(right, int) and right >= 0:
                    if len(left) * right <= MAX_STR_LEN:
                        return left * right
                    raise _UnsafeScript()
                if isinstance(right, str) and isinstance(left, int) and left >= 0:
                    if len(right) * left <= MAX_STR_LEN:
                        return right * left
                    raise _UnsafeScript()
                raise _UnsafeScript()

            # No other ops permitted with strings
            raise _UnsafeScript()

        # Numeric operations
        if not (_is_number(left) and _is_number(right)):
            raise _UnsafeScript()

        try:
            if isinstance(node.op, ast.Add):
                res = left + right
            elif isinstance(node.op, ast.Sub):
                res = left - right
            elif isinstance(node.op, ast.Mult):
                res = left * right
            elif isinstance(node.op, ast.Div):
                res = left / right
            elif isinstance(node.op, ast.FloorDiv):
                res = left // right
            elif isinstance(node.op, ast.Mod):
                res = left % right
            else:
                # Disallow power and any other operators
                raise _UnsafeScript()
        except Exception:
            raise _UnsafeScript()

        if _is_number_in_bounds(res):
            return res
        raise _UnsafeScript()

    # Any other node is disallowed
    raise _UnsafeScript()
